import{_ as p,C as t,o as y,c as h,j as i,a,E as e,a3 as o}from"./chunks/framework.CVjg771q.js";const f=JSON.parse('{"title":"庄子·齐物论","description":"围绕地籁天籁、大知小知、道枢莫若以明、庄周梦蝶展开庄子的齐物思想。","frontmatter":{"title":"庄子·齐物论","description":"围绕地籁天籁、大知小知、道枢莫若以明、庄周梦蝶展开庄子的齐物思想。","category":"guide","aliases":["齐物论","庄子齐物论","zhuangzi chapter 02"],"source":["《庄子》"]},"headers":[],"relativePath":"daoism/zhuang-zi/chapter-02.md","filePath":"daoism/zhuang-zi/chapter-02.md","lastUpdated":1782666543000}'),s={name:"daoism/zhuang-zi/chapter-02.md"};function l(d,n,u,b,c,z){const g=t("DaoReadingPrelude"),m=t("DaoOriginalReading"),r=t("DaoKeywordCards");return y(),h("div",null,[n[0]||(n[0]=i("h1",{id:"庄子·齐物论",tabindex:"-1"},[a("庄子·齐物论 "),i("a",{class:"header-anchor",href:"#庄子·齐物论","aria-label":'Permalink to "庄子·齐物论"'},"​")],-1)),e(g,{title:"从地籁天籁到庄周梦蝶，进入庄子的齐物之境",summary:"齐物论是《庄子》内篇第二篇，也是全书哲学浓度最高的篇章之一。从南郭子綦的「吾丧我」开篇，到庄周梦蝶收束，庄子一层层拆解是非、彼我、梦觉之间的对立，最后提出「天地与我并生，万物与我为一」的齐物境界。",points:[{label:"先看",text:"顺着三籁→大知小知→道枢→梦蝶的人物与意象链条走一遍。"},{label:"再问",text:"庄子为什么反复拆解是非？「莫若以明」到底在说什么？"},{label:"最后",text:"庄周梦蝶不是逃避现实，而是对「我是谁」的最深追问。"}],hint:"齐物论哲学浓度很高，第一次读不必逐句求通，先把几个核心意象（地籁天籁、道枢、环中、物化、梦蝶）立住。"}),n[1]||(n[1]=i("h2",{id:"一、三籁之辩——吾丧我与天籁",tabindex:"-1"},[a("一、三籁之辩——吾丧我与天籁 "),i("a",{class:"header-anchor",href:"#一、三籁之辩——吾丧我与天籁","aria-label":'Permalink to "一、三籁之辩——吾丧我与天籁"'},"​")],-1)),e(m,{paragraphs:["南郭子綦隐机而坐，","仰天而嘘，荅焉似丧其耦。","颜成子游立侍乎前，曰：","何居乎？形固可使如槁木，","而心固可使如死灰乎？","今之隐机者，非昔之隐机者也。","子綦曰：偃，","不亦善乎，而问之也？","今者吾丧我，汝知之乎？","女闻人籁，而未闻地籁，","女闻地籁而未闻天籁夫！","子游曰：敢问其方。","子綦曰：夫大块噫气，","其名为风，是唯无作，","作则万窍怒呺，","而独不闻之翏翏乎？","山林之畏佳，大木百围之窍穴，","似鼻，似口，似耳，","似枅，似圈，似臼，","似洼者，似污者。","激者，謞者，叱者，吸者，","叫者，譹者，宎者，咬者，","前者唱于而随者唱喁。","泠风则小和，飘风则大和，","厉风济则众窍为虚。","而独不见之调调之刁刁乎？","子游曰：","地簌则众窍是已，","人簌则比竹是已，敢问天簌。","子綦曰：","夫吹万不同，而使其自己也，","咸其自取，怒者其谁邪？"]}),e(r,{items:[{term:"南郭子綦",pinyin:["nán","guō","zǐ","qí"],meaning:"楚人，居住南郭，故名南郭子綦。旧说为楚庄王庶出的弟弟，做过楚庄王的司马；疑为庄子中寓托的高士，而非历史人物。隐：凭倚。机：亦作几，案几。"},{term:"嘘",pinyin:["xū"],meaning:"吐气。"},{term:"荅焉",pinyin:["tà","yān"],meaning:"亦作「嗒焉」，离形去智的样子。耦：匹对。庄子认为人是肉体和精神的对立统一体，「耦」在这里即指与精神相对立的躯体。丧其耦，表示精神超脱躯体达到忘我的境界。"},{term:"颜成子游",pinyin:["yán","chéng","zǐ","yóu"],meaning:"子綦的学生，姓颜名偃，子游为字，死后谥成，故名颜成子游。"},{term:"居",pinyin:["jī"],meaning:"表疑问的语气词。"},{term:"槁木",pinyin:["gǎo","mù"],meaning:"干枯的木头。固：诚然。"},{term:"心",pinyin:["xīn"],meaning:"思想，精神。固：岂，难道。"},{term:"隐机者",pinyin:["yǐn","jī","zhě"],meaning:"指南郭子綦。「今之隐机者」与「昔之隐机者」实指一人，意思是南郭子綦今日隐机入神出体与旧时大不一样。"},{term:"偃",pinyin:["yǎn"],meaning:"即颜成子游。"},{term:"而",pinyin:["ér"],meaning:"你，人称代词。「不亦善乎，而问之也」乃是「尔问之不亦善乎」之倒置。"},{term:"簌",pinyin:["lài"],meaning:"箫，古代的一种管状乐器，这里泛指从孔穴里发出的声响。「人簌」即出自人为的声响，与「地簌」「天簌」相对应，所谓「地簌」或「天簌」，即出自自然的声响。"},{term:"敢",pinyin:["gǎn"],meaning:"表示谦敬的副词，含有「冒昧地」、「斗胆地」的意思。方：道术，指所言「地簌」、「天簌」的真实含意。"},{term:"大块",pinyin:["dà","kuài"],meaning:"大地。噫(yī)气：吐气。"},{term:"是",pinyin:["shì"],meaning:"此，这里指风。唯：句中语气词，含有仅此的意思。作：兴起。"},{term:"窍",pinyin:["qiào"],meaning:"孔穴。呺(háo)：亦作「号」，吼叫。"},{term:"翏翏",pinyin:["liú","liú"],meaning:"亦作飂飂，大风呼呼的声响。"},{term:"畏佳",pinyin:["wèi","cuī"],meaning:"亦作「嵔佳」，即嵬崔，山陵高峻的样子。"},{term:"枅",pinyin:["jī"],meaning:"柱头横木。"},{term:"污",pinyin:["wū"],meaning:"停滞不流的水塘。"},{term:"激",pinyin:["jī"],meaning:"水流湍急的声音。"},{term:"謞",pinyin:["xiào"],meaning:"这里用来形容箭头飞去的声响。"},{term:"譹",pinyin:["háo"],meaning:"嚎哭声。"},{term:"宎",pinyin:["yǎo"],meaning:"深而沉。"},{term:"咬",pinyin:["jiāo"],meaning:"鸟鸣叫的声音。一说哀切声。"},{term:"于喁",pinyin:["yú","yú"],meaning:"风吹树动前后相和的声音。"},{term:"泠风",pinyin:["líng","fēng"],meaning:"小风，清风。"},{term:"厉风",pinyin:["lì","fēng"],meaning:"迅猛的暴风。济：止。"},{term:"调调刁刁",pinyin:["tiáo","tiáo","diāo","diāo"],meaning:"风吹草木晃动摇曳的样子。「刁刁」亦作「刀刀」。"},{term:"是",pinyin:["shì"],meaning:"这样。已：矣。"},{term:"比竹",pinyin:["bǐ","zhú"],meaning:"比：并合。竹：这里指并合在一起可以发出声响的、不同形状的竹管。"},{term:"吹万不同",pinyin:["chuī","wàn","bù","tóng"],meaning:"使它们自身发出各种各样的声音。一说「己」当作「已」，是停止的意思，但联系上下文不宜从此解。"},{term:"咸",pinyin:["xián"],meaning:"全。"},{term:"怒",pinyin:["nù"],meaning:"这里是发动的意思。"}]}),n[2]||(n[2]=i("h2",{id:"二、大知小知之辩——成心与真宰",tabindex:"-1"},[a("二、大知小知之辩——成心与真宰 "),i("a",{class:"header-anchor",href:"#二、大知小知之辩——成心与真宰","aria-label":'Permalink to "二、大知小知之辩——成心与真宰"'},"​")],-1)),e(m,{paragraphs:["大知闲闲，小知閒閒；大言炎炎，小言詹詹。其寐也魂交，其觉也形开；与接为搆，日以心斗：缦者，窖者，密者。小恐惴惴，大恐缦缦。其发若机栝，其司是非之谓也；其留如诅盟，其守胜之谓也。其杀若秋冬，以言其日消也；其溺之所为之，不可使复之也；其厌也如缄，以言其老洫也；近死之心，莫使复阳也。喜怒哀乐，虑叹变，姚佚启态。乐出虚，蒸成菌。日夜相代乎前，而莫知其所萌。已乎，已乎！旦暮得此，其所由以生乎！","非彼无我，非我无所取。是亦近矣，而不知其所为使。若有真宰，而特不得其眹，可行已信，而不见其形，有情而无形。百骸、九窍、六藏，赅而存焉，吾谁与为亲？汝皆说之乎？其有私焉？如是皆有为臣妾乎？其臣妾不足以相治乎？其递相为君臣乎？其有真君存焉？如求得其情与不得，无益损乎其真。一受其成形，不亡以待尽。与物相刃相靡，其行尽如驰，而莫之能止，不亦悲乎！终身役役而不见其成功，然疲役而不知其所归，可不哀邪！人谓之不死，奚益！其形化，其心与之然，可不谓大哀乎？人之生也，固若是芒乎？其我独芒，而人亦有不芒者乎？","夫随其成心而师之，谁独且无师乎？奚必知代而心自取者有之？愚者与有焉。未成乎心而有是非，是今日适越而昔至也。是以无有为有。无有为有，虽有神禹且不能知，吾独且奈何哉！"]}),e(r,{items:[{term:"闲闲",pinyin:["xián","xián"],meaning:"广博豁达的样子。"},{term:"閒閒",pinyin:["jiàn","jiàn"],meaning:"「閒」是「间」的古体，今简作「间」，「閒閒」即间间，明察细别的样子。"},{term:"炎炎",pinyin:["yán","yán"],meaning:"猛烈；这里借猛火炎燎之势，比喻说话时气焰盛人。"},{term:"詹詹",pinyin:["zhān","zhān"],meaning:"言语琐细，说个没完。"},{term:"魂交",pinyin:["hún","jiāo"],meaning:"寐：睡眠。魂交：心灵驰躁，神魂交接。"},{term:"形开",pinyin:["xíng","kāi"],meaning:"觉：睡醒。形开：身形开朗，目开意悟。一说形体不宁。"},{term:"搆",pinyin:["gòu"],meaning:"接：接触，这里指与外界环境接触。搆：「构(搆)」字的异体，交合的意思。"},{term:"缦",pinyin:["màn"],meaning:"通作「慢」，疏怠迟缓的意思。"},{term:"窖",pinyin:["jiào"],meaning:"深沉，用心不可捉摸。"},{term:"密",pinyin:["mì"],meaning:"隐秘、谨严。"},{term:"惴惴",pinyin:["zhuì","zhuì"],meaning:"恐惧不安的样子。"},{term:"缦缦",pinyin:["màn","màn"],meaning:"神情沮丧的样子。"},{term:"机栝",pinyin:["jī","guā"],meaning:"机：弩机，弩上的发射部位。栝：箭杆末端扣弦部位。"},{term:"司",pinyin:["sī"],meaning:"主。「司是非」犹言主宰是非，意思是「是」与「非」都由此产生。一说「司」通「伺」，窥伺人之是非的意思。"},{term:"诅盟",pinyin:["zǔ","méng"],meaning:"留：守住，指留存内心。诅盟：誓约；结盟时的誓言，坚守不渝。"},{term:"杀",pinyin:["shài"],meaning:"肃杀，衰败。"},{term:"厌",pinyin:["yā"],meaning:"通作「压」，闭塞的意思。缄：绳索，这里是用绳索加以束缚的意思。"},{term:"洫",pinyin:["xù"],meaning:"败坏。"},{term:"复阳",pinyin:["fù","yáng"],meaning:"复生，恢复生机。"},{term:"虑叹变",pinyin:["lǜ","tàn","biàn"],meaning:"虑：忧虑。叹：感叹。变：反复。(zhè)：通作「慑」，恐惧的意思。"},{term:"姚佚启态",pinyin:["yáo","yì","qǐ","tài"],meaning:"姚：轻浮躁动。佚：奢华放纵。启：这里指放纵情欲而不知收敛。态：这里是故作姿态的意思。"},{term:"乐出虚",pinyin:["yuè","chū","xū"],meaning:"乐声从中空的情态中发出，用管状乐器中空的特点代指乐器本身。"},{term:"蒸成菌",pinyin:["zhēng","chéng","jùn"],meaning:"在暑热潮湿的条件下蒸腾而生各种菌类。"},{term:"萌",pinyin:["méng"],meaning:"萌发、产生。"},{term:"旦暮",pinyin:["dàn","mù"],meaning:"昼夜，这里表示时间很短。此：指上述对立、对应的各种情态形成发生的道理，犹如乐出于虚，菌出于气，一切都形成于「虚」、「无」。"},{term:"彼",pinyin:["bǐ"],meaning:"就字面上讲指「我」的对立面，也可以理解为非我的大自然，甚至包括上述各种情态。"},{term:"取",pinyin:["qǔ"],meaning:"资证，呈现。"},{term:"真宰",pinyin:["zhēn","zǎi"],meaning:"主宰。「真宰」犹如今日言「造世主」，但也可理解为真我，即我身的主宰。"},{term:"眹",pinyin:["zhèn"],meaning:"端倪、征兆。特：但，只。"},{term:"情",pinyin:["qíng"],meaning:"真，指事实上的存在。"},{term:"百骸九窍六藏",pinyin:["bǎi","hái","jiǔ","qiào","liù","zàng"],meaning:"百骸概指骨节（百为概数）。九窍指双眼、双耳、双鼻孔、口、生殖器、肛门。六藏即六脏（心、肺、肝、脾、肾，也有分为左右两肾的）。"},{term:"赅",pinyin:["gāi"],meaning:"齐备。"},{term:"说",pinyin:["yuè"],meaning:"喜悦，这个意义后代写作「悦」。"},{term:"真君",pinyin:["zhēn","jūn"],meaning:"对待「我」来说，「真君」即「真我」、「真心」，对待社会的各种情态说，「真君」就是「真宰」。"},{term:"亡",pinyin:["wáng"],meaning:"亦作「忘」，忘记。一说「亡」为「代」字之讹，变化的意思。尽：耗竭、消亡。"},{term:"相刃相靡",pinyin:["xiāng","rèn","xiāng","mǐ"],meaning:"刃：刀口，这里喻指针锋相对的对立面。靡：倒下，这里是顺应的意思。"},{term:"役役",pinyin:["yì","yì"],meaning:"相当于「役于役」。意思是为役使之物所役使。一说劳苦不休的样子。"},{term:"疲役",pinyin:["pí","yì"],meaning:"犹言疲于役，为役使所疲顿。然(nié)：疲倦困顿的样子。"},{term:"芒",pinyin:["máng"],meaning:"通作「茫」，迷昧无知。"},{term:"成心",pinyin:["chéng","xīn"],meaning:"业已形成的偏执之见。"},{term:"知代",pinyin:["zhī","dài"],meaning:"代：更改，变化。「知代」意思是懂得变化更替的道理。取：资证、取信的意思。"},{term:"未成乎心",pinyin:["wèi","chéng","hū","xīn"],meaning:"比喻没有成见就已经出现是非观念。"},{term:"神禹",pinyin:["shén","yǔ"],meaning:"神明的夏禹。"}]}),n[3]||(n[3]=i("h2",{id:"三、道隐与是非——莫若以明",tabindex:"-1"},[a("三、道隐与是非——莫若以明 "),i("a",{class:"header-anchor",href:"#三、道隐与是非——莫若以明","aria-label":'Permalink to "三、道隐与是非——莫若以明"'},"​")],-1)),e(m,{paragraphs:["夫言非吹也。言者有言，其所言者特未定也。果有言邪？其未尝有言邪？其以为异于音，亦有辩乎？其无辩乎？道恶乎隐而有真伪？言恶乎隐而有是非？道恶乎往而不存？言恶乎存而不可？道隐于小成，言隐于荣华。故有儒墨之是非，以是其所非而非其所是。欲是其所非而非其所是，则莫若以明。","物无非彼，物无非是。自彼则不见，自知则知之。故曰：彼出于是，是亦因彼。彼是，方生之说也。虽然，方生方死，方死方生；方可方不可，方不可方可；因是因非，因非因是。是以圣人不由而照之于天，亦因是也。是亦彼也，彼亦是也。彼亦一是非，此亦一是非。果且有彼是乎哉？果且无彼是乎哉？彼是莫得其偶，谓之道枢。枢始得其环中，以应无穷。是亦一无穷，非亦一无穷也。故曰莫若以明。","以指喻指之非指，不若以非指喻指之非指也；以马喻马之非马，不若以非马喻马之非马也。天地一指也，万物一马也。可乎可，不可乎不可。道行之而成，物谓之而然。恶乎然？然于然。恶乎不然？不然于不然。恶乎可？可于可。恶乎不可？不可于不可。物固有所然，物固有所可；无物不然，无物不可。故为是举莛与楹、厉与西施、恢恑憰怪，道通为一。其分也，成也；其成也，毁也。凡物无成与毁，复通为一。唯达者知通为一，为是不用而寓诸庸。庸也者，用也；用也者，通也；通也者，得也；适得而几矣。因是已，已而不知其然，谓之道。","劳神明为一而不知其同也，谓之朝三。何谓朝三？狙公赋芧曰：「朝三而暮四」。众狙皆怒。曰：「然则朝四而暮三」。众狙皆悦。名实未亏而喜怒为用，亦因是也。是以圣人和之以是非而休乎天钧，是之谓两行。古之人，其知有所至矣。恶乎至？有以为未始有物者，至矣，尽矣，不可以加矣。其次以为有物矣，而未始有封也。其次以为有封焉，而未始有是非也。是非之彰也，道之所以亏也。道之所以亏，爱之所以成。果且有成与亏乎哉？果且无成与亏乎哉？有成与亏，故昭氏之鼓琴也。无成与亏，故昭氏之不鼓琴也。昭文之鼓琴也，师旷之枝策也，惠子之据梧也，三子之知几乎！皆其盛者也，故载之末年。唯其好之也，以异于彼；其好之也，欲以明之。彼非所明而明之，故以坚白之昧终。而其子又以文之纶终，终身无成。若是而可谓成乎？虽我亦成也。若是而不可谓成乎？物与我无成也。是故滑疑之耀，圣人之所图也。为是不用而寓诸庸，此之谓以明。"]}),e(r,{items:[{term:"言非吹",pinyin:["yán","fēi","chuī"],meaning:"风吹出于自然，而辩言之是非出于己见，所以说「言非吹」。"},{term:"音",pinyin:["gòu","yīn"],meaning:"刚刚破卵而出的鸟的叫声。"},{term:"辩",pinyin:["biàn"],meaning:"通作「辨」，分辨、区别。"},{term:"小成",pinyin:["xiǎo","chéng"],meaning:"指一时的、局部的成功。"},{term:"荣华",pinyin:["róng","huá"],meaning:"木草之花，这里喻指华丽的词藻。"},{term:"儒墨",pinyin:["rú","mò"],meaning:"儒家和墨家，战国时期两个政治和哲学流派。"},{term:"莫若以明",pinyin:["mò","ruò","yǐ","míng"],meaning:"传统的解释为「莫如即以本然之明照之」，意思是「不如用其自然加以观察」。姑存此说。"},{term:"方生",pinyin:["fāng","shēng"],meaning:"并存。一说「方」通作「旁」，依的意思。"},{term:"照之于天",pinyin:["zhào","zhī","yú","tiān"],meaning:"由：自，经过。一说用，「不由」就是不用。照：观察。天：这里指事物的自然，即本然。"},{term:"道枢",pinyin:["dào","shū"],meaning:"枢要。大道的关键之处；庄子认为，彼和此是事物对立的两个方面，如果彼和此都失去了相对立的一面，那么这就是道的枢要，即齐物以至齐论的关键。"},{term:"环中",pinyin:["huán","zhōng"],meaning:"环的中心；「得其环中」喻指抓住要害。"},{term:"指",pinyin:["zhǐ"],meaning:"战国名家学派公孙龙子著《指物论》，这里应是针对该篇内容而言，所谓「指」，即组成事物的要素。事物的要素并非事物本身。"},{term:"马",pinyin:["mǎ"],meaning:"跟「指」一样，同是当时论辩的主要论题。名家公孙龙子就曾作《白马篇》，阐述了「白马非马」的观点。"},{term:"莛与楹",pinyin:["tíng","yǔ","yíng"],meaning:"莛：草茎。楹：厅堂前的木柱。代指物之细小者和巨大者。"},{term:"厉与西施",pinyin:["lì","yǔ","xī","shī"],meaning:"厉：通作「疠」，指皮肤溃烂，这里用表丑陋的人。西施：吴王的美姬，古代著名的美人。"},{term:"恢恑憰怪",pinyin:["huī","guǐ","jué","guài"],meaning:"恢：宽大。恑：奇变。憰：诡诈。怪：怪异。四字连在一起，概指千奇百怪的各种事态。"},{term:"分与成",pinyin:["fēn","yǔ","chéng"],meaning:"「分」和「成」也是相对立的，一个事物被分解了，这就意味生成一新的事物。「毁」与「成」也是相对立的，一个新事物通过分解而生成了，这就意味原事物的本有状态必定走向毁灭。"},{term:"寓诸庸",pinyin:["yù","zhū","yōng"],meaning:"寓：寄托。诸：讲作「之于」。庸：指平常之理。一说讲作「用」，含有功用的意思。"},{term:"朝三暮四",pinyin:["zhāo","sān","mù","sì"],meaning:"狙公赋芧(xù)给猴子，说「朝三而暮四」众狙皆怒，说「朝四而暮三」众狙皆悦。名实未亏而喜怒为用，比喻名虽不一，实却无损。"},{term:"天钧",pinyin:["tiān","jūn"],meaning:"钧：通作「均」；「天钧」即自然而又均衡。两行：物与我，即自然界与自我的精神世界都能各得其所，自行发展。"},{term:"未始有物",pinyin:["wèi","shǐ","yǒu","wù"],meaning:"古之人认知的最高境界：有以为未始有物者，至矣，尽矣，不可以加矣。"},{term:"昭氏",pinyin:["zhāo","shì"],meaning:"即昭文，以善于弹琴著称。庄子认为，音本是一个整体，没有高低长短之分就无法演奏。正因为分出音的高低长短才能在琴弦上演奏出来。"},{term:"师旷",pinyin:["shī","kuàng"],meaning:"晋平公时的著名乐师。枝策：用如动词，用枝或策叩击拍节，犹如今天的打拍子。"},{term:"据梧",pinyin:["jù","wú"],meaning:"惠施善辩，「据梧」意思就是靠着桐树高谈阔论。一说「梧」当讲作桐木几案。"},{term:"坚白",pinyin:["jiān","bái"],meaning:"指石的颜色白而质地坚，但「白」和「坚」都独立于「石」之外。公孙龙子曾有「坚白论」之说，庄子是极不赞成的。昧：迷昧。"},{term:"滑疑之耀",pinyin:["gǔ","yí","zhī","yào"],meaning:"滑(gǔ)疑：纷乱的样子，这里指各种迷乱人心的辩说。耀：炫耀。圣人之所图（鄙）：瞧不起，摒弃的意思。"}]}),n[4]||(n[4]=i("h2",{id:"四、天地与我并生——万物为一",tabindex:"-1"},[a("四、天地与我并生——万物为一 "),i("a",{class:"header-anchor",href:"#四、天地与我并生——万物为一","aria-label":'Permalink to "四、天地与我并生——万物为一"'},"​")],-1)),e(m,{paragraphs:["今且有言于此，不知其与是类乎？其与是不类乎？类与不类，相与为类，则与彼无以异矣。虽然，请尝言之。有始也者，有未始有始也者，有未始有夫未始有始也者。有有也者，有无也者，有未始有无也者，有未始有夫未始有无也者。俄而有无矣，而未知有无之果孰有孰无也。今我则已有谓矣，而未知吾所谓之其果有谓乎，其果无谓乎？天下莫大于秋豪之末，而大山为小；莫寿于殇子，而彭祖为夭。天地与我并生，而万物与我为一。既已为一矣，且得有言乎？既已谓之一矣，且得无言乎？一与言为二，二与一为三。自此以往，巧历不能得，而况其凡乎！故自无适有以至于三，而况自有适有乎！无适焉，因是已。","夫道未始有封，言未始有常，为是而有畛也。请言其畛：有左有右，有伦有义，有分有辩，有竞有争，此之谓八德，六合之外，圣人存而不论；六合之内，圣人论而不议。春秋经世先王之志，圣人议而不辩。故分也者，有不分也；辩也者，有不辩也。曰：何也？圣人怀之，众人辩之以相示也。故曰辩也者有不见也。夫大道不称，大辩不言，大仁不仁，不廉不嗛，不勇不忮。道昭而不道，言辩而不及，仁常而不成，廉清而不信，勇忮而不成。五者圆而几向方矣。故知止其所不知，至矣。孰知不言之辩、不道之道？若有能知，此之谓天府。注焉而不满，酌焉而不竭，而不知其所由来，此之谓葆光。"]}),e(r,{items:[{term:"类",pinyin:["lèi"],meaning:"同类、相同。"},{term:"俄而",pinyin:["é","ér"],meaning:"突然。"},{term:"秋豪之末",pinyin:["qiū","háo","zhī","mò"],meaning:"豪：通作「毫」，细毛。末：末稍。秋毫之末比喻事物的细小。"},{term:"大山",pinyin:["dà","shān"],meaning:"一说读如泰山。"},{term:"殇子",pinyin:["shāng","zǐ"],meaning:"未成年而死的人。"},{term:"天地与我并生",pinyin:["tiān","dì","yǔ","wǒ","bìng","shēng"],meaning:"天地与我同时存在，万物与我浑然一体。这是庄子齐物思想的核心命题。"},{term:"巧历",pinyin:["qiǎo","lì"],meaning:"历：历数，计算。巧历即善于计算的人。"},{term:"畛",pinyin:["zhěn"],meaning:"田地里的界路，这里泛指事物、事理间的界线和区分。"},{term:"八德",pinyin:["bā","dé"],meaning:"八类、八种，指左、右、伦、义、分、辩、竞、争八种分别。"},{term:"六合",pinyin:["liù","hé"],meaning:"天、地和东、西、南、北四方。存而不论：保留而不加论说。"},{term:"春秋经世",pinyin:["chūn","qiū","jīng","shì"],meaning:"这里泛指古代历史，并非指战国以前的那一段历史年代。经世：经纶世事。"},{term:"怀之",pinyin:["huái","zhī"],meaning:"囊括于胸，指不去分辨物我和是非，把物与我、是与非都容藏于身。"},{term:"大道不称",pinyin:["dà","dào","bù","chēng"],meaning:"大道不可名称。大辩不言：最高的辩论是不用言语的。"},{term:"嗛",pinyin:["qiān"],meaning:"通「谦」，谦逊。"},{term:"忮",pinyin:["zhì"],meaning:"伤害。"},{term:"天府",pinyin:["tiān","fǔ"],meaning:"指自然生成的府库，也就是整个宇宙。"},{term:"葆光",pinyin:["bǎo","guāng"],meaning:"葆(bǎo)：藏，隐蔽。「葆光」即潜隐光亮而不露。"}]}),n[5]||(n[5]=i("h2",{id:"五、尧问舜——十日并出",tabindex:"-1"},[a("五、尧问舜——十日并出 "),i("a",{class:"header-anchor",href:"#五、尧问舜——十日并出","aria-label":'Permalink to "五、尧问舜——十日并出"'},"​")],-1)),e(m,{paragraphs:["故昔者尧问于舜曰：「我欲伐宗、脍、胥敖，南面而不释然，其故何也？」舜曰：「夫三子者，犹存乎蓬艾之间。若不释然，何哉？昔者十日并出，万物皆照，而况德之进乎日者乎！」齧缺问乎王倪曰：「子知物之所同是乎？」曰：「吾恶乎知之！」「子知子之所不知邪？」曰：「吾恶乎知之！」「然则物无知邪？」曰：「吾恶乎知之！虽然，尝试言之。庸讵知吾所谓知之非不知邪？庸讵知吾所谓不知之非知邪？且吾尝试问乎女：民湿寝则腰疾偏死，然乎哉？木处则惴慄恂惧，猨猴然乎哉？三者孰知正处？民食刍豢，麋鹿食荐，蝍蛆甘带，鸱鸦耆鼠，四者孰知正味？猨猵狙以为雌，麋与鹿交，与鱼游。毛嫱丽姬，人之所美也，鱼见之深入，鸟见之高飞，麋鹿见之决骤。四者孰知天下之正色哉？自我观之，仁义之端，是非之塗，樊然殽乱，吾恶能知其辩！」齧缺曰：「子不知利害，则至人固不知利害乎？」王倪曰：「至人神矣！大泽焚而不能热，河汉沍而不能寒，疾雷破山飘风振海而不能惊。若然者，乘云气，骑日月，而游乎四海之外。死生无变于己，而况利害之端乎！」"]}),e(r,{items:[{term:"宗脍胥敖",pinyin:["zōng","kuài","xū","áo"],meaning:"三个小国国名。"},{term:"南面",pinyin:["nán","miàn"],meaning:"君主临朝；古代帝王上朝理事总坐北朝南。释然：不耿介于怀的样子。"},{term:"三子者",pinyin:["sān","zǐ","zhě"],meaning:"指上述三国的国君。存乎蓬艾之间：比喻国微君卑，不足与之计较。"},{term:"十日并出",pinyin:["shí","rì","bìng","chū"],meaning:"指古代寓言中十个太阳一并出来的故事，庄子借此比喻阳光普照到每一个地方。"},{term:"齧缺",pinyin:["niè","quē"],meaning:"传说中的古代贤人，实为庄子寓言故事中虚拟的人物。王倪：同为庄子虚构的贤人。"},{term:"庸讵",pinyin:["yōng","jù"],meaning:"怎么、哪里。"},{term:"",pinyin:["qiū"],meaning:"「鳅」字的异体，即泥鳅。"},{term:"刍豢",pinyin:["chú","huàn"],meaning:"刍：草。豢：养。「刍豢」，用草喂养，这里代指家畜、牲口。"},{term:"荐",pinyin:["jiàn"],meaning:"美草。麋：一种食草的珍贵兽类，与鹿同科。"},{term:"蝍蛆甘带",pinyin:["jí","jū","gān","dài"],meaning:"蝍蛆：蜈蚣。甘：甜美，嗜好。带：小蛇。「甘带」意思是以小蛇为美食。"},{term:"鸱鸦耆鼠",pinyin:["chī","yā","shì","shǔ"],meaning:"鸱(chī)：猫头鹰。耆：亦写作「嗜」，嗜好。猫头鹰与乌鸦以鼠为美食。"},{term:"毛嫱丽姬",pinyin:["máo","qiáng","lì","jī"],meaning:"古代著名的美人。决骤：迅疾奔跑。"},{term:"樊然殽乱",pinyin:["fán","rán","yáo","luàn"],meaning:"樊然：杂乱的样子。殽(yáo)：这里讲作「淆」，混杂的意思。"},{term:"至人神矣",pinyin:["zhì","rén","shén","yǐ"],meaning:"至人神妙不测。大泽焚而不能热，河汉沍(hù)而不能寒——超越一切物理限制。"}]}),n[6]||(n[6]=i("h2",{id:"六、瞿鹊子问长梧子——大梦大觉",tabindex:"-1"},[a("六、瞿鹊子问长梧子——大梦大觉 "),i("a",{class:"header-anchor",href:"#六、瞿鹊子问长梧子——大梦大觉","aria-label":'Permalink to "六、瞿鹊子问长梧子——大梦大觉"'},"​")],-1)),e(m,{paragraphs:["瞿鹊子问乎长梧子曰：「吾闻诸夫子，圣人不从事于务，不就利；不违害，不喜求，不缘道；无谓有谓，有谓无谓，而游乎尘垢之外。夫子以为孟浪之言，而我以为妙道之行也。吾子以为奚若？」长梧子曰：「是黄帝之所听荧也，而丘也何足以知之！且女亦大早计，见卵而求时夜，见弹而求鸮炙。予尝为女妄言之，女以妄听之。奚旁日月，挟宇宙？为其脗合，置其滑涽，以隶相尊。众人役役，圣人愚芚，参万岁而一成纯。万物尽然，而以是相蕴。","予恶乎知说生之非惑邪！予恶乎知恶死之非弱丧而不知归者邪！丽之姬，艾封人之子也。晋国之始得之也，涕泣沾襟，及其至于王所，与王同筐床，食刍豢，而后悔其泣也。予恶乎知夫死者不悔其始之蕲生乎！梦饮酒者，旦而哭泣；梦哭泣者，旦而田猎。方其梦也，不知其梦也。梦之中又占其梦焉，觉而后知其梦也。且有大觉而后知此其大梦也，而愚者自以为觉，窃窃然知之。君乎、牧乎，固哉！丘也与女，皆梦也；予谓女梦，亦梦也。是其言也，其名为吊诡。万世之后而一遇大圣，知其解者，是旦暮遇之也！","既使我与若辩矣，若胜我，我不若胜，若果是也，我果非也邪？我胜若，若不吾胜，我果是也，而果非也邪？其或是也，其或非也邪？其俱是也，其俱非也邪？我与若不能相知也，则人固受其黮，吾谁使正之？使同乎若者正之？既与若同矣，恶能正之！使同乎我者正之？既同乎我矣，恶能正之！使异乎我与若者正之？既异乎我与若矣，恶能正之！使同乎我与若者正之？既同乎我与若矣，恶能正之！然则我与若与人，俱不能相知也，而待彼也邪？化声之相待，若其不相待，和之以天倪，因之以曼衍，所以穷年也。何谓和之以天倪？曰：是不是，然不然。是若果是也，则是之异乎不是也亦无辩；然若果然也，则然之异乎不然也亦无辩。忘年忘义，振于无竟，故寓诸无竟」。"]}),e(r,{items:[{term:"瞿鹊子",pinyin:["qú","què","zǐ"],meaning:"与长梧子同为杜撰的人名。"},{term:"孟浪",pinyin:["mèng","làng"],meaning:"言语轻率不当。"},{term:"听荧",pinyin:["tīng","yíng"],meaning:"疑惑不明。"},{term:"卵求时夜",pinyin:["luǎn","qiú","shí","yè"],meaning:"见卵而求时夜（司夜之鸡），比喻过早计虑。见弹而求鸮炙：见到弹丸就想吃烤鸮肉，同理。"},{term:"脗合",pinyin:["wěn","hé"],meaning:"「吻」字的异体，吻合。"},{term:"滑涽",pinyin:["gǔ","hūn"],meaning:"滑(gǔ)：通作「汩」，淆乱的意思。涽：乱。"},{term:"愚芚",pinyin:["yú","chūn"],meaning:"芚(chūn)：浑然无所觉察和识别的样子。众人役役于分辨是非，圣人则愚芚。"},{term:"参万岁",pinyin:["cān","wàn","suì"],meaning:"参：糁糅。万岁：年代久远。意思是糅合历史的长久变异与沉浮。纯：精粹不杂，指不为纷乱和差异所乱。"},{term:"丽姬",pinyin:["lì","jī"],meaning:"丽：丽戎，春秋时的小国。姬：美女。丽姬宠于晋献公，素以美貌称于世。初被掳时涕泣沾襟，后来后悔当初的哭泣。"},{term:"大梦",pinyin:["dà","mèng"],meaning:"「且有大觉而后知此其大梦也」——只有大彻大悟之后才知道人生不过一场大梦。"},{term:"吊诡",pinyin:["dì","guǐ"],meaning:"奇特、怪异。"},{term:"黮",pinyin:["dǎn","àn"],meaning:"昏暗不明的样子。「」是「暗」字的异体。"},{term:"天倪",pinyin:["tiān","ní"],meaning:"倪：分，「天倪」即天然的分际。「和之以天倪」即用天然的分际来调和是非。曼衍：变化发展。"},{term:"忘年忘义",pinyin:["wàng","nián","wàng","yì"],meaning:"忘掉生死（年）、忘掉是非（义），畅游于无穷的境界之中。"}]}),n[7]||(n[7]=i("h2",{id:"七、罔两问景——有待与无待",tabindex:"-1"},[a("七、罔两问景——有待与无待 "),i("a",{class:"header-anchor",href:"#七、罔两问景——有待与无待","aria-label":'Permalink to "七、罔两问景——有待与无待"'},"​")],-1)),e(m,{paragraphs:["罔两问景曰：「曩子行，今子止；曩子坐，今子起。何其无特操与？」景曰：「吾有待而然者邪？吾所待又有待而然者邪？吾待蛇蚹蜩翼邪？恶识所以然？恶识所以不然？」"]}),e(r,{items:[{term:"罔两",pinyin:["wǎng","liǎng"],meaning:"影子之外的微阴。景（影）：影子。"},{term:"曩",pinyin:["nǎng"],meaning:"从前，刚才。"},{term:"特操",pinyin:["tè","cāo"],meaning:"独立的操守。"},{term:"有待",pinyin:["yǒu","dài"],meaning:"有所依赖。影子依赖形体，形体又有它所依赖的——层层追问，不知最终的「所以然」。"},{term:"蛇蚹蜩翼",pinyin:["shé","fù","tiáo","yì"],meaning:"蚹：蛇肚腹下的横鳞，蛇赖此行走。蜩：蝉。蛇赖蚹行，蝉赖翼飞，各自有所依赖。"}]}),n[8]||(n[8]=i("h2",{id:"八、庄周梦蝶——物化",tabindex:"-1"},[a("八、庄周梦蝶——物化 "),i("a",{class:"header-anchor",href:"#八、庄周梦蝶——物化","aria-label":'Permalink to "八、庄周梦蝶——物化"'},"​")],-1)),e(m,{paragraphs:["昔者庄周梦为胡蝶，栩栩然胡蝶也，自喻适志与！不知周也。俄然觉，则蘧蘧然周也。不知周之梦为胡蝶与，胡蝶之梦为周与？周与胡蝶，则必有分矣。此之谓物化。"]}),e(r,{items:[{term:"胡蝶",pinyin:["hú","dié"],meaning:"亦作蝴蝶。"},{term:"栩栩然",pinyin:["xǔ","xǔ","rán"],meaning:"欣然自得的样子。"},{term:"适志",pinyin:["shì","zhì"],meaning:"合乎心意，心情愉快。喻：通作「愉」。"},{term:"俄然",pinyin:["é","rán"],meaning:"突然。"},{term:"蘧蘧然",pinyin:["qú","qú","rán"],meaning:"惊惶的样子。"},{term:"物化",pinyin:["wù","huà"],meaning:"事物自身的变化。外物与自我的交合，一切事物浑而为一。庄周与蝴蝶必有分，却又可以相互转化——这就是「齐物」的最终落点。"}]}),n[9]||(n[9]=o('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>齐物论是《庄子》中哲学密度最高的一篇。它从「吾丧我」的体道境界开始，经由地籁天籁的比喻、大知小知的心理分析、道枢与环中的正反辩证、朝三暮四的寓言，最终落在庄周梦蝶的「物化」意象上。全篇的核心，是不断拆解人对是非、彼我、生死、梦觉的执着，指出万物本来相通。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>齐物论之重要，在于它给出了庄子认识论的核心框架：①「莫若以明」——不要执着于你自己那一边的「明」，而要看到天地本然的明；②「道枢」与「环中」——抓住是非彼此相待而生的枢要，才能以不变应无穷；③「物化」——万物之间并非隔绝，而是可以相互转化、通达为一的。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>今天读齐物论，最实用的入口是问自己：① 我是否常常陷在「我对你错」的辩论里，忘了跳出对立看更大的局面？② 我是否把某些观念当成了「成心」，用它去衡量一切？③ 庄周梦蝶不是虚无，而是提醒人：你以为清醒的「自我」，也许不过是一场更大的梦中的一个角色。这让你更焦虑，还是更释然？</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《庄子》</li><li>太极书馆：《庄子》第二页</li></ul>',13))])}const q=p(s,[["render",l]]);export{f as __pageData,q as default};
